const body = $input.item.json.body || $input.item.json;

const eventType = body.event?.type || "";
if (eventType && eventType !== "messages") {
  return { json: { normalized: { is_valid: false, event: eventType } } };
}

const messages = body.messages || [];
const msg = messages[0] || {};
const messageType = msg.type || "text";
const isAudio = messageType === "audio" || messageType === "voice" || messageType === "ptt";
let messageText = "";
if (messageType === "text") {
  messageText = msg.text?.body || "";
}
const fromMe = msg.from_me || false;

if (fromMe) {
  return { json: { normalized: { is_valid: false, from_me: true, event: eventType } } };
}

let chatId = msg.chat_id || msg.from || "";
chatId = chatId.split("@")[0];

let phoneDisplay = chatId;
if (chatId.length >= 8) {
  phoneDisplay = "+" + chatId;
}

let audioId = "";
let audioUrl = "";
if (isAudio) {
  const mediaObj = msg.voice || msg.audio || msg.media || {};
  audioId = mediaObj.id || "";
  if (audioId) {
    audioUrl = `https://gate.whapi.cloud/media/${audioId}`;
  }
}

const isImage = messageType === "image" || messageType === "sticker" || messageType === "document";
const isValid = !fromMe && (messageText.length > 0 || isAudio);

return {
  json: {
    normalized: {
      message_id: msg.id || "",
      chat_id: chatId,
      phone_display: phoneDisplay,
      from: msg.from || "",
      from_name: msg.from_name || "Cliente",
      device: body.channel_id || "",
      message_type: messageType,
      is_audio: isAudio,
      is_image: isImage,
      has_text: messageText.length > 0,
      text: messageText,
      audio_id: audioId,
      audio_url: audioUrl,
      from_me: fromMe,
      is_valid: isValid,
      event: eventType,
      timestamp: new Date().toISOString()
    },
    raw: body
  }
};

const transcription = $input.item.json.text || "";
const original = $('Normalizar').item.json.normalized;

console.log('🎤 Audio transcrito:', transcription);

const updated = {
  ...original,
  text: transcription,
  has_text: Boolean(transcription.length > 0),
  is_valid: Boolean(transcription.length > 0 && !original.from_me),
  is_audio: false,
  audio_transcribed: true
};

return {
  json: {
    normalized: updated
  }
};

const chatId = $input.item.json.normalized.chat_id;
const texto  = $input.item.json.normalized.text || "";
const ts     = Date.now();

if (!global.msgQueue) global.msgQueue = {};

if (!global.msgQueue[chatId]) {
  global.msgQueue[chatId] = { messages: [], lastTs: 0 };
}

global.msgQueue[chatId].messages.push(texto);
global.msgQueue[chatId].lastTs = ts;

console.log(`📥 Cola [${chatId}]: ${global.msgQueue[chatId].messages.length} mensaje(s)`);

return { json: $input.item.json };

const chatId = $input.item.json.normalized.chat_id;
const ts     = Date.now();

if (!global.msgQueue) global.msgQueue = {};

const cola = global.msgQueue[chatId];

if (!cola || cola.messages.length === 0) {
  return { json: $input.item.json };
}

const tiempoDesdeUltimo = ts - cola.lastTs;

if (tiempoDesdeUltimo < 6000) {
  console.log(`⏸️ Ejecución abortada para [${chatId}] — hay mensajes más recientes`);
  global.msgQueue[chatId].messages = [];
  return [];
}

const textoCombinado = cola.messages
  .filter(m => m && m.trim().length > 0)
  .join(" ");

console.log(`✅ Procesando [${chatId}]: "${textoCombinado}"`);

global.msgQueue[chatId] = { messages: [], lastTs: 0 };

const normalizedActualizado = {
  ...$input.item.json.normalized,
  text: textoCombinado,
  has_text: textoCombinado.length > 0
};

return { json: { normalized: normalizedActualizado } };

const textoIA = $input.item.json.output || "";

console.log('📥 Respuesta cruda de IA:', textoIA);

let datos = {
  text_response: "",
  order_complete: false,
  send_menu: false,
  order_details: null
};

const inicioJSON = textoIA.indexOf('{');
const finJSON = textoIA.lastIndexOf('}') + 1;

if (inicioJSON !== -1 && finJSON > inicioJSON) {
  try {
    let jsonLimpio = textoIA.substring(inicioJSON, finJSON);
    jsonLimpio = jsonLimpio
      .replace(/[\u0000-\u001F\u007F-\u009F]/g, '')
      .replace(/\n/g, '\\n');
    datos = JSON.parse(jsonLimpio);
    console.log('✅ JSON parseado correctamente');
  } catch (error) {
    console.error('❌ Error al parsear JSON:', error.message);
    const match = textoIA.match(/\"text_response\"\s*:\s*\"([^\"]+)\"/);
    if (match) {
      datos.text_response = match[1].replace(/\\n/g, '\n');
    } else {
      datos.text_response = textoIA.replace(/```json|```/g, '').trim();
    }
  }
} else {
  datos.text_response = textoIA.trim();
}

if (!datos.text_response || datos.text_response.length === 0) {
  datos.text_response = "Disculpa, tuve un problema procesando tu mensaje. ¿Podrías repetirlo? 🙏";
}

if (typeof datos.order_complete !== 'boolean') datos.order_complete = false;
if (typeof datos.send_menu !== 'boolean') datos.send_menu = false;

datos.text_response = datos.text_response
  .replace(/\\n/g, '\n')
  .replace(/\\"/g, '"')
  .replace(/\\\\/g, '\\')
  .trim();

if (datos.order_details && datos.order_details.total) {
  datos.order_details.total = datos.order_details.total.toString().replace('$', '').trim();
}

let chat_id = "", from = "", phone_display = "", from_name = "";

try {
  const normalizerData = $('Normalizar').item.json.normalized;
  if (normalizerData) {
    chat_id = normalizerData.chat_id || "";
    from = normalizerData.from || "";
    phone_display = normalizerData.phone_display || chat_id;
    from_name = normalizerData.from_name || "Cliente";
  }
} catch (error) {
  console.error('⚠️ Error al obtener datos del nodo Normalizar:', error.message);
}

return {
  json: {
    text_response: datos.text_response,
    pedido_completo: datos.order_complete,
    enviar_menu: datos.send_menu,
    detalles_pedido: datos.order_details,
    chat_id: chat_id,
    from: from,
    phone_display: phone_display,
    from_name: from_name
  }
};
